import React, { useState } from "react";
import { Box, Button, Container, TextField, Typography, ToggleButton, ToggleButtonGroup, Paper, Alert, CircularProgress } from "@mui/material";
import axios from "axios";

export default function Register() {
  const [formData, setFormData] = useState({ fullName: "", email: "", mobile: "", role: "user" });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const handleChange = e => setFormData(p => ({ ...p, [e.target.name]: e.target.value }));
  const handleRoleChange = (_, newRole) => newRole && setFormData(p => ({ ...p, role: newRole }));

  const validate = () => {
    if (!formData.fullName || !formData.email || !formData.mobile) { setError("All fields required"); return false; }
    if (!/^[6-9]\d{9}$/.test(formData.mobile)) { setError("Invalid mobile number"); return false; }
    setError(""); return true;
  };

  const handleSubmit = async e => {
    e.preventDefault();
    if (!validate()) return;
    setLoading(true);
    try {
      const res = await axios.post("http://localhost:5000/api/auth/signup", formData);
      if (res.data.success) setSuccess(res.data.message);
      else setError(res.data.message || "Signup failed");
    } catch (err) {
      setError(err.response?.data?.message || "Server error");
    } finally { setLoading(false); }
  };

  return (
    <Container maxWidth="sm">
      <Paper sx={{ p: 4, mt: 5 }}>
        <Typography variant="h4" align="center" gutterBottom>Rider App</Typography>
        {error && <Alert severity="error">{error}</Alert>}
        {success && <Alert severity="success">{success}</Alert>}
        <Box component="form" onSubmit={handleSubmit}>
          <TextField fullWidth label="Full Name" name="fullName" value={formData.fullName} onChange={handleChange} margin="normal" required />
          <TextField fullWidth label="Email" name="email" value={formData.email} onChange={handleChange} margin="normal" required />
          <TextField fullWidth label="Mobile" name="mobile" value={formData.mobile} onChange={handleChange} margin="normal" required />
          <Typography variant="subtitle1">Role</Typography>
          <ToggleButtonGroup value={formData.role} exclusive onChange={handleRoleChange} fullWidth sx={{ mb: 2 }}>
            <ToggleButton value="user">User</ToggleButton>
            <ToggleButton value="owner">Owner</ToggleButton>
          </ToggleButtonGroup>
          <Button type="submit" fullWidth variant="contained" disabled={loading}>
            {loading ? <CircularProgress size={24} /> : "Register"}
          </Button>
        </Box>
      </Paper>
    </Container>
  );
}
